var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루. 일어설 수 있겠어?","JPN":"ルル。立てる？","ENG":"Lulu? Can you get up?","TWN":"露露，你站得起來嗎？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"으응. 글린다는……?","JPN":"うん。グリンダは……？","ENG":"Yes. And you, Glinda...?","TWN":"嗯嗯，格琳達呢……？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"나야 뭐. 이 정도는 익숙해. 맨날 벌받는 게 일상이었으니까.","JPN":"私はまあ。このくらいは慣れてる。毎日お仕置き受けてたから。","ENG":"Me? I’m used to it. Getting punishment was like a daily routine for me here.","TWN":"這對我來說根本是家常便飯，早就習慣啦。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그런 거에 익숙해지지 마. 그런 얘기 들으면 속상해져…….","JPN":"慣れちゃだめだよ。そんな話を聞くと胸が痛くなる……","ENG":"Don’t say that you’re used to it. It makes me sad...","TWN":"這種事不需要習慣，你這麼說我會難過……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아참! 헤론, 헤론 님은?","JPN":"そうだ！　ヘロン、ヘロン様は？","ENG":"Oh, right! Heron! Where’s Madam Heron?","TWN":"對了！海倫…海倫夫人呢？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"도망갔어. 한참 전에.","JPN":"逃げた。とっくに。","ENG":"She ran away. A long time ago.","TWN":"她早就溜了。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그런……!","JPN":"そんな……！","ENG":"No...!","TWN":"可惡……！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그 여자 신경 쓸 시간 없어. 곧 조직원들이 몰려올 거야. 서둘러 움직여야 해.","JPN":"あんな女を気にしてる暇はない。すぐ組織員が来るよ。早く動かなきゃ。","ENG":"We don’t have time for her. This place will soon be overrun with guards. We need to get going.","TWN":"現在沒時間管她，其他人很快就會趕到這裡來，我們必須加快動作。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"애들은 아직 자고 있겠지? 빨리 가서 깨우자.","JPN":"子どもたちはまだ寝てるよな？　早く行って起こそう。","ENG":"The other kids should still be asleep, right? Let’s go wake them up.","TWN":"他們應該還在睡吧？快去叫醒他們吧！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"어쩌면 도로시가 난리를 피웠으니 깨어 있을지도 몰라.","JPN":"もしかしたらドロシーが騒がしくしたから、もう起きてるかもしれない。","ENG":"But after the mess you made, Dorothy, I think they might be awake.","TWN":"你剛踹得那麼大聲，說不定早就被你吵醒了。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"저기. 애들이라니? 깨우러 간다는 게 무슨 소리야?","JPN":"あのさ。子どもたちって？　起こしに行くって、どういうこと？","ENG":"Uh, kids? What do you mean \\"waking them up?\\"","TWN":"請問，他們是誰？叫醒他們又是什麼意思？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"우리는…… 이곳 아이들을 구하러 왔어.","JPN":"私たちは……ここの子どもたちを助けるために来たの。","ENG":"We’re... here to save the kids.","TWN":"我們……是來救這裡的孩子的。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"언제까지 이곳에서 이용만 당하다 버림받게 둘 순 없으니까.","JPN":"いつまでもここで利用されて捨てられるのを放っておくわけにはいかないからね。","ENG":"We can’t let them be abused and abandoned here.","TWN":"總不能放任他們繼續這樣利用孩子，利用完就把人踢一邊。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"맞아. 그리고 모두 내…… 친구들이기도 하고.","JPN":"そうさ。それにみんな私の……友達なんだし。","ENG":"She’s right. Plus, they’re all... my friends.","TWN":"沒錯，而且那些孩子……全都是我的朋友。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"피치 못하게 먼저 도망쳤어. 곧바로 부딪치기엔 우리가 너무 약했거든.","JPN":"事情があって先に逃げたんだ。すぐ立ち向かうにはワタシたちが弱すぎたから。","ENG":"We had no choice but to run away first. We were too weak back then.","TWN":"我們之前是逼不得已先暫時逃跑，因為當時的能力還不足以與他們正面對決。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"지금도 그다지 강해졌다고 하긴 어렵지만, 전보다는 나아졌으니까.","JPN":"今もそんなに強くなったとは言えないけど、昔よりはマシだ。","ENG":"Although we can’t say we are strong, we are stronger than we were before.","TWN":"雖然現在也沒厲害到哪裡去，但至少比那時候好。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"숙소 옮겼어. 너희가 부순 곳으로 다시 나가서, 왼쪽으로 쭉 가면 허름한 건물이 하나 나올 거야.","JPN":"宿舎は移動したよ。アンタたちが壊した場所から外に出て、左にまっすぐ行くと古びた建物が一軒ある。","ENG":"They relocated the dorms. Go out the way you came, then turn left and continue straight until you come across an old run-down building.","TWN":"宿舍搬家了，你們從進來的地方出去，往左一直走，就會看到一棟破房子。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};